using UnityEngine;
using Climbing;

public class ComponentFinder
{
    public static string Find()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "ClimbController not found in scene";
        return $"Found ClimbController on GameObject: {cc.gameObject.name} (InstanceID: {cc.gameObject.GetInstanceID()})";
    }
}
